import { renderHook, act } from '@testing-library/react';
import { useTurnLogic } from '../dungeon-use-turn-logic';

describe('TurnCombatRegression', () => {
  const createMockConfig = (sessionOverrides = {}) => {
    const gameSession = {
      currentTurn: 1,
      heroes: [
        { heroId: 1, turnOrder: 1, currentBody: 5, isEscaped: false, activeStatus: [], x: 0, y: 0, hero: { classe: 'Mago' } },
        { heroId: 2, turnOrder: 2, currentBody: 5, isEscaped: false, activeStatus: [], x: 1, y: 1, hero: { classe: 'Elfo' } }
      ],
      monsters: [],
      ...sessionOverrides
    };

    return {
      gameSession,
      visibilityMap: { data: [] },
      onNotify: jest.fn(),
      trapsLogic: {},
      heroStatsLogic: { 
        calculateStats: jest.fn(() => ({ movimento: 2, canAttackDiagonal: false, canAttackRanged: false })),
        calculateAttackDice: jest.fn(() => 2),
        canAttackTwice: jest.fn(() => false),
        getConsumableWeaponId: jest.fn(() => null)
      },
      hooksPathfinding: {
        calculatePath: jest.fn(() => [{x: 1, y: 1}])
      },
      combatLogic: {
        resolveCombat: jest.fn(() => ({ damageDealt: 1 }))
      },
      mapInteractionLogic: { 
        isFrontOfDoor: jest.fn(() => null),
        openPassage: jest.fn()
      },
      visibilityCalc: {
        hasLineOfSight: jest.fn(() => true)
      },
      sessionManager: {
        advanceTurn: jest.fn(),
        clearCurrentHeroStatus: jest.fn(),
        clearHeroStatusEverywhere: jest.fn(),
        moveCurrentHeroTo: jest.fn(),
        executeMissionScripts: jest.fn(),
        resolveHeroAttack: jest.fn(),
        markCurrentHeroEscaped: jest.fn()
      }
    };
  };

  test('Scenario: Roll Movement Re-Enabled On New Hero Turn', () => {
    const config = createMockConfig();
    const { result, rerender } = renderHook((props) => useTurnLogic(props), { initialProps: config });

    act(() => {
      result.current.rollMovement();
    });
    expect(result.current.movementPoints).toBeGreaterThanOrEqual(1);

    act(() => {
      result.current.forceTurnExhausted();
    });
    expect(result.current.turnPhase.HasMoved).toBe(true);
    expect(result.current.turnPhase.HasPerformedAction).toBe(true);

    act(() => {
      result.current.endTurn();
    });

    expect(config.sessionManager.advanceTurn).toHaveBeenCalledWith(2, null);

    const newConfig = {
      ...config,
      gameSession: {
        ...config.gameSession,
        currentTurn: 2
      }
    };

    rerender(newConfig);

    expect(result.current.movementPoints).toBeNull();
    expect(result.current.turnPhase.HasMoved).toBe(false);
    expect(result.current.turnPhase.HasPerformedAction).toBe(false);
    expect(result.current.isMoving).toBe(false);
  });

  test('Scenario: Dead Hero Cannot Act And Is Skipped', () => {
    const config = createMockConfig({
      heroes: [
        { heroId: 1, turnOrder: 1, currentBody: 0, isEscaped: false, activeStatus: [], x: 0, y: 0, hero: { classe: 'Mago' } }
      ]
    });
    const { result } = renderHook((props) => useTurnLogic(props), { initialProps: config });

    act(() => {
      result.current.rollMovement();
    });
    expect(result.current.movementPoints).toBeNull();

    act(() => {
      result.current.handleBoardClick(1, 1);
    });
    expect(result.current.isMovingStarted).toBe(false);

    act(() => {
      result.current.handleMonsterClick(1);
    });
    expect(result.current.turnPhase.HasPerformedAction).toBe(false);
  });

  test('Scenario: Escaped Hero Cannot Act And Is Skipped', () => {
    const config = createMockConfig({
      heroes: [
        { heroId: 1, turnOrder: 1, currentBody: 5, isEscaped: true, activeStatus: [], x: 0, y: 0, hero: { classe: 'Mago' } }
      ]
    });
    const { result } = renderHook((props) => useTurnLogic(props), { initialProps: config });

    act(() => {
      result.current.rollMovement();
    });
    expect(result.current.movementPoints).toBeNull();

    act(() => {
      result.current.handleBoardClick(1, 1);
    });
    expect(result.current.isMovingStarted).toBe(false);

    act(() => {
      result.current.handleMonsterClick(1);
    });
    expect(result.current.turnPhase.HasPerformedAction).toBe(false);
  });

  test('Scenario: Invisible Passage Expires At Turn End', () => {
    const config = createMockConfig({
      heroes: [
        { heroId: 1, turnOrder: 1, currentBody: 5, isEscaped: false, activeStatus: ['InvisiblePassage'], x: 0, y: 0, hero: { classe: 'Mago' } },
        { heroId: 2, turnOrder: 2, currentBody: 5, isEscaped: false, activeStatus: [], x: 1, y: 1, hero: { classe: 'Elfo' } }
      ]
    });
    const { result } = renderHook((props) => useTurnLogic(props), { initialProps: config });

    act(() => {
      result.current.endTurn();
    });

    expect(config.onNotify).toHaveBeenCalledWith("L'effetto di Passaggio Invisibile svanisce.");
    expect(config.sessionManager.advanceTurn).toHaveBeenCalledWith(2, "InvisiblePassage");
  });
});